/**
 * Model IDs supported by the PixelArt image generation API.
 */
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'retro-diffusion'
  | (string & {});

/**
 * Settings for the PixelArt image generation model.
 */
export interface PixelArtImageSettings {
  /**
   * The size of the generated image (e.g. "512x512", "1024x1024").
   */
  size?: string;

  /**
   * The visual style to apply to the generated image.
   * - "pixel": Classic pixel art style
   * - "retro": Retro/vintage aesthetic
   * - "8bit": 8-bit video game style
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density of the generated image. Higher values produce
   * more detailed pixel art. Typical range: 1–16.
   */
  pixelDensity?: number;
}

