import { ImageModelV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';
import { VERSION } from './version';

/**
 * Configuration options for the PixelArt provider.
 */
export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API. Defaults to "https://api.pixelart.ai/v1".
   */
  baseURL?: string;

  /**
   * PixelArt API key. Defaults to the PIXELART_API_KEY environment variable.
   */
  apiKey?: string;

  /**
   * Custom HTTP headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation for making HTTP requests.
   */
  fetch?: FetchFunction;
}

/**
 * The PixelArt provider interface.
 * Only supports image generation — no text, chat, or embeddings.
 */
export interface PixelArtProvider {
  /**
   * Returns a PixelArt image generation model for the given model ID.
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Alias for `image()`.
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

const PIXELART_BASE_URL = 'https://api.pixelart.ai/v1';

/**
 * Creates a PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 *
 * const pixelart = createPixelArt({ apiKey: 'my-key' });
 * const model = pixelart.image('pixelart-v1', { style: 'pixel', pixelDensity: 8 });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? PIXELART_BASE_URL;

  const getHeaders = (): Record<string, string | undefined> => ({
    Authorization: `Bearer ${loadApiKey({
      apiKey: options.apiKey,
      environmentVariableName: 'PIXELART_API_KEY',
      description: 'PixelArt',
    })}`,
    'User-Agent': `ai-sdk/pixelart/${VERSION}`,
    ...options.headers,
  });

  const createImageModel = (
    modelId: PixelArtImageModelId,
    settings: PixelArtImageSettings = {},
  ): ImageModelV3 =>
    new PixelArtImageModel(modelId, settings, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    image: createImageModel,
    imageModel: createImageModel,
  };
}

/**
 * Default PixelArt provider instance using environment variable PIXELART_API_KEY.
 */
export const pixelart = createPixelArt();

