import { z } from 'zod/v4';
import { createJsonErrorResponseHandler } from '@ai-sdk/provider-utils';

export const pixelartErrorDataSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.union([z.string(), z.number()]).nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelartErrorDataSchema>;

export const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorDataSchema,
  errorToMessage: data => data.error.message,
});

content.thinking:
Looking at the OpenAI error handler:
```typescript
import { z } from 'zod/v4';
import { createJsonErrorResponseHandler } from '@ai-sdk/provider-utils';

export const openaiErrorDataSchema = z.object({...});
export type OpenAIErrorData = z.infer<typeof openaiErrorDataSchema>;
export const openaiFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: openaiErrorDataSchema,
  errorToMessage: data => data.error.message,
});
```

The `createJsonErrorResponseHandler` uses `zodSchema` internally, or it accepts a zod schema directly. Looking at the signature:


I'm noticing that `createJsonErrorResponseHandler` accepts raw Zod schemas directly for the `errorSchema` parameter, whereas `createJsonResponseHandler` for success responses requires a `Schema<T>` wrapper from provider-utils. In the OpenAI implementation, they're passing `openaiErrorDataSchema` as a plain `z.object(...)` directly into the error handler, which suggests the error handler has different type requirements than the success handler. The zod/v4 subpath is available as a peer dependency in a real build, so `pixelartErrorDataSchema` will be properly typed and `data` will correctly infer its type. The `pixelart-error.ts` implementation matches OpenAI's pattern exactly. I also need to update the fetch type in my provider file to use `FetchFunction` from `@ai-sdk/provider-utils` instead of `typeof globalThis.fetch`.

